message.content:
{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires analyzing a large set of rules to determine if a specific causal chain exists. I will split this into rule extraction/mapping and logical chain verification.",
  "helpers": [
    {
      "label": "rule_extractor",
      "instructions": "Analyze the provided 45 rules of the board game. Identify and list every rule that mentions the butterfly, the fish, or any intermediate entities/actions that could link the butterfly to the fish. Create a directed graph or a list of conditional statements showing how one state leads to another."
    },
    {
      "label": "logic_verifier",
      "instructions": "Using the list of rule chains provided, attempt to trace a path from the action of the butterfly revealing a secret to the fish receiving it. Determine if the rules provide a definitive 'yes', a definitive 'no', or if the information is insufficient to conclude the outcome. If the chain is broken or incomplete, conclude that the answer is unknown."
    }
  ],
  "synthesis_brief": "Combine the extracted rule chains to see if a complete logical path exists from the butterfly to the fish. If the path is complete and leads to the fish, the answer is yes; if the path is blocked or explicitly prevents it, the answer is no; if the path is incomplete or missing necessary links, the answer is unknown."
}

